const leads = $input.first().json.data || [];
const scored = leads.map(l => {
  const ws = parseInt(l.websiteScore) || 0;
  const ss = parseInt(l.socialScore) || 0;
  const ev = l.emailValid === 'valid' ? 20 : 0;
  const finalScore = Math.round((ws * 0.4) + (ss * 0.3) + (ev * 0.3));
  let segment = 'COLD';
  let action = 'nurture';
  if (finalScore >= 80) { segment = 'HOT'; action = 'send_now'; }
  else if (finalScore >= 60) { segment = 'WARM'; action = 'batch_send'; }
  else if (finalScore >= 40) { segment = 'COLD'; action = 'nurture'; }
  else { segment = 'DEAD'; action = 'archive'; }
  return {...l, finalScore, segment, action, decidedAt: new Date().toISOString()};
});
return {leads: scored, hot: scored.filter(l => l.segment === 'HOT').length, warm: scored.filter(l => l.segment === 'WARM').length, cold: scored.filter(l => l.segment === 'COLD').length, dead: scored.filter(l => l.segment === 'DEAD').length};
